import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Divider } from '@mui/material';
import { Info } from '@mui/icons-material';
import response from './response.json';

interface ParkingData {
  location: string;
  availableSpots: number;
  nearestLocation: {
    name: string;
    distance: string;
    availableSpots: number;
  };
  hourlyRate: number;
}

export default function Widget() {
  const parkingData = response.data as ParkingData;
  const { theme, primaryColor, accentColor } = response.meta;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 300,
        maxWidth: 400,
        bgcolor: theme === 'dark' ? '#1E1E1E' : '#FFFFFF',
        color: theme === 'dark' ? '#F5F5F5' : '#1E1E1E',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              {parkingData.location}
            </Typography>
            <Typography variant="h4" sx={{ my: 0.5 }}>
              {parkingData.availableSpots} Spots Available
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Hourly Rate: ${parkingData.hourlyRate.toFixed(2)}
            </Typography>
          </Box>
          <Divider sx={{ bgcolor: primaryColor }} />
          <Box>
            <Typography variant="body2" color="text.secondary">
              Nearest Location
            </Typography>
            <Typography variant="h6" sx={{ my: 0.5, color: primaryColor }}>
              {parkingData.nearestLocation.name}
            </Typography>
            <Stack direction="row" justifyContent="space-between" alignItems="center">
              <Typography variant="body2" color="text.secondary">
                {parkingData.nearestLocation.distance}
              </Typography>
              <Typography variant="body2" sx={{ color: accentColor }}>
                {parkingData.nearestLocation.availableSpots} Spots
              </Typography>
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
